import React, { useState, useEffect } from 'react';

const Main = ({ restaurants, onRestaurantClick }) => {
  const [filteredRestaurants, setFilteredRestaurants] = useState(restaurants);
  const [activeFilter, setActiveFilter] = useState('all');
  const [selectedRestaurant, setSelectedRestaurant] = useState(null);
  const [relatedRestaurants, setRelatedRestaurants] = useState([]);
  const [showRelatedModal, setShowRelatedModal] = useState(false);

  useEffect(() => {
    setFilteredRestaurants(restaurants);
  }, [restaurants]);

  const handleFilterClick = (filter) => {
    setActiveFilter(filter);
    let filtered = [...restaurants];
    
    switch(filter) {
      case 'rating':
        filtered = restaurants.filter(r => r.rating >= 4.5);
        break;
      case 'fast':
        filtered = restaurants.filter(r => parseInt(r.deliveryTime) <= 30);
        break;
      case 'offer':
        filtered = restaurants.filter(r => parseInt(r.discount) >= 40);
        break;
      default:
        filtered = restaurants;
    }
    
    setFilteredRestaurants(filtered);
  };

  const handleSearch = (query) => {
    if (!query) {
      setFilteredRestaurants(restaurants);
      return;
    }
    const filtered = restaurants.filter(r => 
      r.name.toLowerCase().includes(query.toLowerCase()) || 
      r.cuisine.toLowerCase().includes(query.toLowerCase())
    );
    setFilteredRestaurants(filtered);
  };

  // Find related restaurants based on cuisine matching
  const findRelatedRestaurants = (restaurant) => {
    const cuisineTypes = restaurant.cuisine.split(',').map(c => c.trim().toLowerCase());
    
    const scored = restaurants
      .filter(r => r.id !== restaurant.id)
      .map(r => {
        let score = 0;
        const rCuisines = r.cuisine.split(',').map(c => c.trim().toLowerCase());
        
        cuisineTypes.forEach(c => {
          rCuisines.forEach(rc => {
            if (rc.includes(c) || c.includes(rc)) {
              score += 2;
            }
          });
        });
        
        return { restaurant: r, score };
      })
      .filter(item => item.score > 0)
      .sort((a, b) => b.score - a.score);
    
    const related = scored.slice(0, Math.max(20, scored.length));
    return related.map(item => item.restaurant);
  };

  const handleCardClick = (restaurant) => {
    setSelectedRestaurant(restaurant);
    const related = findRelatedRestaurants(restaurant);
    setRelatedRestaurants(related);
    setShowRelatedModal(true);
  };

  const closeRelatedModal = () => {
    setShowRelatedModal(false);
    setSelectedRestaurant(null);
    setRelatedRestaurants([]);
  };

  return (
    <>
      {/* Hero Section */}
      <section className="hero">
        <div className="hero-content">
          <h1>Discover the best food & drinks</h1>
          <p>Order food from the best restaurant near you</p>
          
          <div className="quick-links">
            <a href="#" className="quick-link"><i className="fas fa-birthday-cake"></i> Birthday Party</a>
            <a href="#" className="quick-link"><i className="fas fa-leaf"></i> Healthy Food</a>
            <a href="#" className="quick-link"><i className="fas fa-pizza-slice"></i> Pizza</a>
            <a href="#" className="quick-link"><i className="fas fa-drumstick-bite"></i> Chicken</a>
          </div>
        </div>
      </section>

      {/* Main Content */}
      <main className="main-content">
        <h2 className="section-title">Restaurant near you</h2>
        
        {/* Filters */}
        <div className="filters">
          <button 
            className={`filter-btn ${activeFilter === 'all' ? 'active' : ''}`} 
            data-filter="all"
            onClick={() => handleFilterClick('all')}
          >
            <i className="fas fa-border-all"></i> All
          </button>
          <button 
            className={`filter-btn ${activeFilter === 'rating' ? 'active' : ''}`} 
            data-filter="rating"
            onClick={() => handleFilterClick('rating')}
          >
            <i className="fas fa-star"></i> Top Rated
          </button>
          <button 
            className={`filter-btn ${activeFilter === 'fast' ? 'active' : ''}`} 
            data-filter="fast"
            onClick={() => handleFilterClick('fast')}
          >
            <i className="fas fa-bolt"></i> Fast Delivery
          </button>
          <button 
            className={`filter-btn ${activeFilter === 'offer' ? 'active' : ''}`} 
            data-filter="offer"
            onClick={() => handleFilterClick('offer')}
          >
            <i className="fas fa-tag"></i> Offers
          </button>
          <button className="filter-btn">
            <i className="fas fa-rupee-sign"></i> Budget Friendly
          </button>
          <button className="filter-btn">
            <i className="fas fa-filter"></i> More Filters
          </button>
        </div>
        
        {/* Restaurant Grid */}
        <div className="restaurant-grid" id="restaurantGrid">
          {filteredRestaurants.map(restaurant => (
            <div 
              className="restaurant-card" 
              key={restaurant.id} 
              onClick={() => onRestaurantClick && onRestaurantClick(restaurant.id)}
            >
              <div className="restaurant-image">
                <img src={restaurant.image} alt={restaurant.name} />
                <div className="discount-badge">{restaurant.discount}</div>
              </div>
              <div className="restaurant-info">
                <div className="restaurant-name">{restaurant.name}</div>
                <div className="restaurant-cuisine">{restaurant.cuisine}</div>
                <div className="restaurant-details">
                  <span className="rating">★ {restaurant.rating}</span>
                  <span className="delivery-time">⏱ {restaurant.deliveryTime}</span>
                </div>
              </div>
            </div>
          ))}
        </div>
      </main>

      {/* Location Section */}
      <section className="location-section">
        <h2 className="section-title">Find Us Here</h2>
        <div className="location-container">
          <div className="location-map">
            <iframe 
              src="https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d3800.45678912345!2d81.804!3d16.98!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x0%3A0x0!2zMTbCsDU4JzUwLjAiTiA4McKwNDgnMjAuMCJF!5e0!3m2!1sen!2sin!4v1600000000000!5m2!1sen!2sin"
              width="100%" 
              height="400" 
              style={{ border: 0 }} 
              allowFullScreen="" 
              loading="lazy" 
              referrerPolicy="no-referrer-when-downgrade"
              title="Restaurant Location"
            />
          </div>
          <div className="location-info">
            <h3>Yeswanth's Healthy Kitchen</h3>
            <div className="address-detail">
              <i className="fas fa-map-marker-alt"></i>
              <div>
                <p><strong>Address:</strong></p>
                <p>46-7-26/1, Danavaipeta</p>
                <p>Above Meg Unisex Lounge</p>
                <p>Rajahmundry - 533101</p>
              </div>
            </div>
            <div className="address-detail">
              <i className="fas fa-phone-alt"></i>
              <div>
                <p><strong>Contact:</strong></p>
                <p>Order now: +91 98765 43210</p>
              </div>
            </div>
            <div className="address-detail">
              <i className="fas fa-clock"></i>
              <div>
                <p><strong>Delivery Hours:</strong></p>
                <p>8:00 AM - 10:00 PM</p>
              </div>
            </div>
            <a 
              href="https://www.google.com/maps/dir//Yeswanth's+Healthy+Kitchen,+Rajahmundry" 
              target="_blank" 
              rel="noopener noreferrer" 
              className="directions-btn"
            >
              <i className="fas fa-directions"></i> Get Directions
            </a>
          </div>
        </div>
      </section>

      {/* Footer */}
      <footer className="footer">
        <div className="footer-content">
          <div className="footer-section">
            <h4>About Yeswanth's Healthy Kitchen</h4>
            <ul>
              <li><a href="#">About Us</a></li>
              <li><a href="#">Culture</a></li>
              <li><a href="#">Blog</a></li>
              <li><a href="#">Careers</a></li>
              <li><a href="#">Financial Information</a></li>
            </ul>
          </div>
          <div className="footer-section">
            <h4>For Restaurants</h4>
            <ul>
              <li><a href="#">Partner With Us</a></li>
              <li><a href="#">Apps For You</a></li>
              <li><a href="#">Restaurant Owner</a></li>
              <li><a href="#">Advertise</a></li>
            </ul>
          </div>
          <div className="footer-section">
            <h4>Learn More</h4>
            <ul>
              <li><a href="#">Privacy</a></li>
              <li><a href="#">Terms</a></li>
              <li><a href="#">Security</a></li>
              <li><a href="#">Sitemap</a></li>
            </ul>
          </div>
          <div className="footer-section">
            <h4>Social Links</h4>
            <div className="social-links">
              <a href="#"><i className="fab fa-facebook"></i></a>
              <a href="#"><i className="fab fa-instagram"></i></a>
              <a href="#"><i className="fab fa-twitter"></i></a>
              <a href="#"><i className="fab fa-youtube"></i></a>
            </div>
          </div>
        </div>
        <div className="footer-bottom">
          <p>By continuing past this page, you agree to our Terms of Service, Cookie Policy, Privacy Policy and Content Policies. All trademarks are properties of their respective owners.</p>
          © 2024 Yeswanth's Healthy Kitchen - All rights reserved
        </div>
      </footer>
    </>
  );
};

export default Main;
